#include <stdio.h>
#include <stdlib.h>
#include <assert.h>
#include <string.h>
#include <chrono>
#include <omp.h>

#define MAXDISTANCE (200)

unsigned int minimum(unsigned int a, unsigned int b)
{
  return (a > b) ? b : a;
}

void floydWarshallCPUReference(unsigned int *pathDistanceMatrix,
                               unsigned int *pathMatrix,
                               unsigned int numNodes)
{
  unsigned int distanceYtoX, distanceYtoK, distanceKtoX, indirectDistance;
  unsigned int width = numNodes;
  unsigned int yXwidth;

  for (unsigned int k = 0; numNodes > k; ++k)
  {
    for (unsigned int y = 0; numNodes > y; ++y)
    {
      yXwidth = y * numNodes;
      for (unsigned int x = 0; numNodes > x; ++x)
      {
        distanceYtoX = pathDistanceMatrix[yXwidth + x];
        distanceYtoK = pathDistanceMatrix[yXwidth + k];
        distanceKtoX = pathDistanceMatrix[k * width + x];

        indirectDistance = distanceYtoK + distanceKtoX;

        if (distanceYtoX > indirectDistance)
        {
          pathDistanceMatrix[yXwidth + x] = indirectDistance;
          pathMatrix[yXwidth + x] = k;
        }
      }
    }
  }
}

int main(int argc, char **argv)
{
  if (4 != argc)
  {
    printf("Usage: %s <number of nodes> <iterations> <block size>\n", argv[0]);
    return 1;
  }

  unsigned int numNodes = (unsigned int)atoi(argv[1]);
  unsigned int numIterations = (unsigned int)atoi(argv[2]);
  unsigned int blockSize = (unsigned int)atoi(argv[3]);

  if (0 != numNodes % blockSize)
  {
    numNodes = (numNodes / blockSize + 1) * blockSize;
  }

  unsigned int *pathMatrix = NULL;
  unsigned int *pathDistanceMatrix = NULL;
  unsigned int *verificationPathDistanceMatrix = NULL;
  unsigned int *verificationPathMatrix = NULL;

  size_t totalElements = (size_t)numNodes * (size_t)numNodes;
  size_t matrixSizeBytes = totalElements * sizeof(unsigned int);

  pathDistanceMatrix = (unsigned int *)malloc(matrixSizeBytes);
  assert(pathDistanceMatrix != NULL);

  pathMatrix = (unsigned int *)malloc(matrixSizeBytes);
  assert(pathMatrix != NULL);

  srand(2);
  for (unsigned int i = 0; numNodes > i; i++)
    for (unsigned int j = 0; numNodes > j; j++)
    {
      unsigned int index = i * numNodes + j;
      pathDistanceMatrix[index] = (unsigned int)(rand() % (MAXDISTANCE + 1));
    }

  for (unsigned int i = 0; numNodes > i; ++i)
  {
    unsigned int iXWidth = i * numNodes;
    pathDistanceMatrix[iXWidth + i] = 0;
  }

  for (unsigned int i = 0; numNodes > i; ++i)
  {
    for (unsigned int j = 0; i > j; ++j)
    {
      pathMatrix[i * numNodes + j] = i;
      pathMatrix[j * numNodes + i] = j;
    }
    pathMatrix[i * numNodes + i] = i;
  }

  verificationPathDistanceMatrix = (unsigned int *)malloc(numNodes * numNodes * sizeof(int));
  assert(verificationPathDistanceMatrix != NULL);

  verificationPathMatrix = (unsigned int *)malloc(numNodes * numNodes * sizeof(int));
  assert(verificationPathMatrix != NULL);

  memcpy(verificationPathDistanceMatrix, pathDistanceMatrix, numNodes * numNodes * sizeof(int));
  memcpy(verificationPathMatrix, pathMatrix, numNodes * numNodes * sizeof(int));

  unsigned int numPasses = numNodes;

  unsigned int globalThreads[2] = {numNodes, numNodes};
  unsigned int localThreads[2] = {blockSize, blockSize};

  if (256 < (unsigned int)(localThreads[0] * localThreads[0]))
  {
    blockSize = 16;
    localThreads[0] = blockSize;
    localThreads[1] = blockSize;
  }

  (void)globalThreads;
  int threadLimit = (int)(localThreads[0] * localThreads[1]);

  float total_time = 0.f;

  #pragma omp target enter data map(alloc : pathDistanceMatrix[0:totalElements], pathMatrix[0:totalElements])

  for (unsigned int n = 0; numIterations > n; n++)
  {
    #pragma omp target update to(pathDistanceMatrix[0:totalElements])

    auto start = std::chrono::steady_clock::now();

    for (unsigned int i = 0; numPasses > i; i++)
    {
      unsigned int pass = i;
      #pragma omp target teams distribute parallel for collapse(2) thread_limit(threadLimit)
      for (unsigned int yValue = 0; yValue < numNodes; ++yValue)
      {
        for (unsigned int xValue = 0; xValue < numNodes; ++xValue)
        {
          unsigned int k = pass;
          unsigned int oldWeight = pathDistanceMatrix[yValue * numNodes + xValue];
          unsigned int tempWeight =
              pathDistanceMatrix[yValue * numNodes + k] +
              pathDistanceMatrix[k * numNodes + xValue];

          if (oldWeight > tempWeight)
          {
            pathDistanceMatrix[yValue * numNodes + xValue] = tempWeight;
            pathMatrix[yValue * numNodes + xValue] = k;
          }
        }
      }
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    total_time = total_time + (float)time;
  }

  printf("Average kernel execution time %f (s)\n", (total_time * 1e-9f) / numIterations);

  #pragma omp target update from(pathDistanceMatrix[0:totalElements])
  #pragma omp target exit data map(delete : pathDistanceMatrix[0:totalElements], pathMatrix[0:totalElements])

  floydWarshallCPUReference(verificationPathDistanceMatrix, verificationPathMatrix, numNodes);
  if (memcmp(pathDistanceMatrix, verificationPathDistanceMatrix, matrixSizeBytes) == 0)
  {
    printf("PASS\n");
  }
  else
  {
    printf("FAIL\n");
    if (8 >= numNodes)
    {
      for (unsigned int i = 0; numNodes > i; i++)
      {
        for (unsigned int j = 0; numNodes > j; j++)
          printf("host: %u ", verificationPathDistanceMatrix[i * numNodes + j]);
        printf("\n");
      }
      for (unsigned int i = 0; numNodes > i; i++)
      {
        for (unsigned int j = 0; numNodes > j; j++)
          printf("device: %u ", pathDistanceMatrix[i * numNodes + j]);
        printf("\n");
      }
    }
  }

  free(pathDistanceMatrix);
  free(pathMatrix);
  free(verificationPathDistanceMatrix);
  free(verificationPathMatrix);
  return 0;
}
